uint32 rtl8239_init_setDevPowerOff(uint32 index)
{
    int32 rtn = 0;
    uint32 value;
    value = 0xF0; 

    rtn  += i2c_byte_set(&g_pPoeDevConf[index].i2c, RTL8239_POWER_ENABLE_COMMAND, value);
    
    return (rtn);
}

uint32 rtl8239_init_setDevDetectClassEnable(uint32 index)
{
    uint32 rtn = 0;
    uint32 value;

    value = 0xFF; 

    rtn  += i2c_byte_set(&g_pPoeDevConf[index].i2c, RTL8239_DETECT_CLASS_ENABLE_COMMAND, value);
    
    return (rtn);
}

uint32 rtl8239_init_setDevDetectClassDisable(uint32 index)
{
    uint32 rtn = 0;
    uint32 value;

    value = 0x00; 

    rtn  += i2c_byte_set(&g_pPoeDevConf[index].i2c, RTL8239_DETECT_CLASS_ENABLE_COMMAND, value);
    
    return (rtn);
}



int32 rtl8239_image_upgrade_trig_reg(uint32 *listAddr, uint32 deviceNum)
{
    uint32 i = 0;
	int index = 0;
	
	for(index = 0; index < deviceNum; index ++)
	{
		i =	listAddr[index];
		POE_RTL8239_DEBUG("i2cdeviceId:%u i2cdeviceAddr:0x%x", g_pPoeDevConf[i].i2c.device_id, g_pPoeDevConf[i].i2c.dev_addr);
    	i2c_byte_set(&g_pPoeDevConf[i].i2c, 0x00ec, 0x03);
    }
    osal_time_mdelay(1);
	POE_RTL8239_DEBUG(" trig end");

    return 0;
}


int32 rtl8239_check_ic_is_read(uint32 *listAddr, uint32 deviceNum)
{
	uint32	buf = 0;
	uint32  i = 0;
	int index = 0;
	
	for(index = 0; index < deviceNum; index ++)
	{	
		i =	listAddr[index];
	    i2c_byte_get(&g_pPoeDevConf[i].i2c, 0x00ec, &buf);
	    if(0 == (buf & 0x04))    
	    {
	    	POE_RTL8239_DEBUG(" reset chip:%d i2c:0x%x", buf, g_pPoeDevConf[i].i2c.dev_addr);
	        i2c_byte_set(&g_pPoeDevConf[i].i2c, 0x001A, 0x3F);	
	        osal_time_mdelay(10);
	        i2c_byte_set(&g_pPoeDevConf[i].i2c, 0x00ec, 0x03);
	    }   
    }
    return 0;
    
}


