uint32 poe_rtl8239_get(uint32 devNum)
{
    uint32 i = 0;
    uint32 tmpVal = 0;
    uint32 statusVal = 0;
    uint32 tmpLsbVal = 0;
    uint32 tmpMsbVal = 0;
    uint32 tempVal = 0;
	

    
    SYS_ERR_CHK(i2c_byte_get(&g_pPoeDevConf[devNum].i2c, RTL8239_POWER_STATUS_COMMAND, &statusVal));
   	SYS_ERR_CHK(i2c_byte_get(&g_pPoeDevConf[devNum].i2c, RTL8239_TEMPERATURE_COMMAND, &tempVal));
    tempVal = CONVERT_TEMP_RTL8239(tempVal);
    for(i = 0; i < g_pPoeDevConf[devNum].portNum; i++)
    {
        g_pPortData[devNum][i].portEnable = (statusVal & (1 << i)) >> i;
        g_pPortData[devNum][i].portPwGood = (statusVal & (0x10 << i)) >> (i + 4);
        g_pPortData[devNum][i].portTemperature = tempVal;
        if(g_pPortData[devNum][i].portEnable && g_pPortData[devNum][i].portPwGood)
        {
			SYS_ERR_CHK(i2c_byte_get(&g_pPoeDevConf[devNum].i2c, (RTL8239_PORT_1_STATUS_COMMAND + i), &tmpVal));
	        g_pPortData[devNum][i].portDetClass = (tmpVal & 0xF);
	        g_pPortData[devNum][i].portClassSts = (tmpVal >> 4) & 0xF;
	        tmpVal = (tmpVal >> 4) & 0xF;
	        if(CLS_LVL_UNKNOWN == tmpVal)
	        {
	            g_pPortData[devNum][i].portStatus = SYS_PD_CLASS_UNKNOWN;
	        }
	        else if ((CLS_LVL_1 <= tmpVal) && (tmpVal <= CLS_LVL_4))
	        {
	            g_pPortData[devNum][i].portStatus = tmpVal;
	        }
	        else if ((CLS_LVL_5 <= tmpVal) && (tmpVal <= CLS_LVL_8))
	        {
	            g_pPortData[devNum][i].portStatus = tmpVal;
	        }
	        else if(CLS_LVL_0 == tmpVal)
	        {
	            g_pPortData[devNum][i].portStatus = SYS_PD_CLASS0_13W;
	        }
	        else
	        {
				g_pPortData[devNum][i].portStatus = SYS_PD_CLASS_END;
	        }

			
	        SYS_ERR_CHK(i2c_byte_get(&g_pPoeDevConf[devNum].i2c, (RTL8239_PORT_1_CURRENT_LSB_COMMAND + i * 4), &tmpLsbVal));
	        SYS_ERR_CHK(i2c_byte_get(&g_pPoeDevConf[devNum].i2c, (RTL8239_PORT_1_CURRENT_MSB_COMMAND + i * 4), &tmpMsbVal));
	        g_pPortData[devNum][i].portCurrent = ((((tmpMsbVal & 0xFF) << 8) | tmpLsbVal) * 250 / 8192);

	        if(g_pPortData[devNum][i].portCurrent)
	        {
		        SYS_ERR_CHK(i2c_byte_get(&g_pPoeDevConf[devNum].i2c, (RTL8239_PORT_1_VOLTAGE_LSB_COMMAND + i * 4), &tmpLsbVal));
		        SYS_ERR_CHK(i2c_byte_get(&g_pPoeDevConf[devNum].i2c, (RTL8239_PORT_1_VOLTAGE_MSB_COMMAND + i * 4), &tmpMsbVal));
		        g_pPortData[devNum][i].portVoltage = ((((tmpMsbVal & 0x7F) << 8) | tmpLsbVal) / RTL8239_VOLTAGE_SCALE_FACTOR);
	        }
	        else
	        {
				g_pPortData[devNum][i].portVoltage = 0;
	        }
        }
        else
        {
			g_pPortData[devNum][i].portDetClass = 0;
			g_pPortData[devNum][i].portClassSts = 0;
			g_pPortData[devNum][i].portStatus = 0;
			g_pPortData[devNum][i].portCurrent = 0;
			g_pPortData[devNum][i].portVoltage = 0;
        }
    }

    return 0;
}


