uint32 board_poe_rtl8239_firmware_init(uint32 *listAddr, uint32 deviceNum, uint32 boardcastDev)
{
    uint32 ret = 0;

	POE_RTL8239_DEBUG("deviceNum:%u boardcastDev:%u", deviceNum, boardcastDev);
	
    
    ret = rtl8239_init_DeviceFirmwareRevChk(listAddr, deviceNum);
    if(ret == 0)
    {
    	return SYS_ERR_OK;
    }
    else if(ret == SYS_ERR_FAILED)
    {
		return SYS_ERR_CHIP_NOT_SUPPORTED;
    }

    
    rtl8239_image_upgrade_trig_reg(listAddr, deviceNum);

   	
   	rtl8239_check_ic_is_read(listAddr, deviceNum);
   	
   	
   	POE_RTL8239_DEBUG("boarddev i2cdeviceId:%u i2cdeviceAddr:0x%x datalenth:%u", g_pPoeDevConf[boardcastDev].i2c.device_id, g_pPoeDevConf[boardcastDev].i2c.dev_addr, g_pPoeDevConf[boardcastDev].i2c.data_width);
    rtl8239_transmit_image_packages_boardcast(&g_pPoeDevConf[boardcastDev].i2c);

	
    rtl8239_check_image_upgrade_pass(listAddr, deviceNum);
    POE_RTL8239_DEBUG(" pass OK  ");

    return SYS_ERR_OK;
}

